import React, { useEffect, useState } from "react";
import { Link } from "react-router-dom";
import Navbar from "../components/Navbar";
import { getMatches } from "../services/api";

function Matches() {
  const [matches, setMatches] = useState([]);
  const [error, setError] = useState("");

  useEffect(() => {
    const fetchMatches = async () => {
      try {
        const data = await getMatches();
        setMatches(data);
      } catch (err) {
        setError(err.message);
      }
    };

    fetchMatches();
  }, []);

  return (
    <div>
      <Navbar />

      <div className="container page-section">
        <h1 className="section-title">Tìm trận bóng</h1>
        <p className="section-subtitle">
          Xem các trận đang có và đăng ký tham gia cùng những người chơi khác.
        </p>

        {error && <p className="error-text">{error}</p>}

        <div className="fields-grid">
          {matches.map((match) => (
            <div key={match.id} className="field-card">
              <div className="field-image">Trận bóng</div>

              <div className="field-content">
                <h3 className="field-title">{match.title}</h3>

                <p className="field-info">
                  <strong>Địa điểm:</strong> {match.location}
                </p>

                <p className="field-info">
                  <strong>Thời gian:</strong> {match.time}
                </p>

                <p className="field-info">
                  <strong>Số người tối đa:</strong> {match.max_players}
                </p>

                <div className="field-actions">
                  <Link to={`/matches/${match.id}`}>
                    <button className="btn-detail">Xem chi tiết</button>
                  </Link>
                </div>
              </div>
            </div>
          ))}
        </div>
      </div>
    </div>
  );
}

export default Matches;
